INSERT INTO stations (id, name, address, latitude, longitude, status, open_time, description, images) VALUES
(1, '图书馆站', '宿迁职业技术学院图书馆一楼大厅', 34.0199, 118.2905, 1, '07:00-22:00', '紧邻图书馆借阅大厅，安静环境适合边学习边充电', '["https://picsum.photos/seed/station1/400/300"]');
INSERT INTO stations (id, name, address, latitude, longitude, status, open_time, description, images) VALUES
(2, '第一食堂站', '宿迁职业技术学院第一食堂门口', 34.0212, 118.2893, 1, '06:30-21:30', '食堂入口右侧，用餐高峰期人流量大，顺路借还方便', '["https://picsum.photos/seed/station2/400/300"]');
INSERT INTO stations (id, name, address, latitude, longitude, status, open_time, description, images) VALUES
(9, '万达广场站', '宿迁市宿城区万达广场1号门入口', 34.025, 118.31, 1, '09:00-22:00', '万达广场1楼服务台旁，宿迁核心商圈，逛街购物随时借还', '["https://picsum.photos/seed/station9/400/300"]');
INSERT INTO stations (id, name, address, latitude, longitude, status, open_time, description, images) VALUES
(10, '宝龙城市广场站', '宿迁市宿城区宝龙城市广场1楼大厅', 34.01, 118.305, 1, '09:00-22:00', '宝龙广场中庭扶梯旁，商业核心区域，客流量大', '["https://picsum.photos/seed/station10/400/300"]');
INSERT INTO stations (id, name, address, latitude, longitude, status, open_time, description, images) VALUES
(11, '第一人民医院站', '宿迁市第一人民医院门诊大厅', 34.033, 118.298, 1, '00:00-24:00', '门诊大厅一楼导诊台对面，24小时全天候服务，满足医患应急充电需求', '["https://picsum.photos/seed/station11/400/300"]');
INSERT INTO stations (id, name, address, latitude, longitude, status, open_time, description, images) VALUES
(12, '宿迁学院站', '宿迁学院图书馆一楼', 34.002, 118.27, 1, '07:00-22:00', '宿迁学院校园核心区域，服务广大师生日常充电需求', '["https://picsum.photos/seed/station12/400/300"]');
INSERT INTO stations (id, name, address, latitude, longitude, status, open_time, description, images) VALUES
(13, '汽车客运站', '宿迁汽车客运站候车大厅', 33.998, 118.28, 1, '06:00-20:00', '候车大厅安检口左侧，出行途中手机没电不用愁', '["https://picsum.photos/seed/station13/400/300"]');
INSERT INTO stations (id, name, address, latitude, longitude, status, open_time, description, images) VALUES
(14, '项王故里站', '宿迁市宿城区项王故里景区入口', 33.995, 118.283, 1, '08:00-18:00', '景区游客中心大厅，游览西楚霸王故里，随时保持电量满满', '["https://picsum.photos/seed/station14/400/300"]');
INSERT INTO stations (id, name, address, latitude, longitude, status, open_time, description, images) VALUES
(15, '湖滨公园站', '宿迁市湖滨新区湖滨公园游客中心', 34.035, 118.31, 1, '08:00-18:00', '游客中心进门处，骆马湖畔休闲漫步也能随时充电', '["https://picsum.photos/seed/station15/400/300"]');
INSERT INTO stations (id, name, address, latitude, longitude, status, open_time, description, images) VALUES
(16, '水韵城站', '宿迁市宿城区水韵城购物中心B1层', 34.008, 118.298, 1, '09:00-22:00', 'B1美食广场入口，餐饮娱乐一站式，等餐时即可充满电', '["https://picsum.photos/seed/station16/400/300"]');
INSERT INTO stations (id, name, address, latitude, longitude, status, open_time, description, images) VALUES
(17, '金鹰购物中心站', '宿迁市宿城区金鹰国际购物中心1楼', 34.015, 118.302, 1, '09:00-22:00', '1楼化妆品区旁，高端商圈配套，购物体验更贴心', '["https://picsum.photos/seed/station17/400/300"]');
INSERT INTO stations (id, name, address, latitude, longitude, status, open_time, description, images) VALUES
(18, '宿迁市中医院站', '宿迁市中医院门诊大厅一楼', 34.028, 118.272, 1, '00:00-24:00', '中医门诊大厅左侧，24小时全天候守护健康与电量', '["https://picsum.photos/seed/station18/400/300"]');
INSERT INTO stations (id, name, address, latitude, longitude, status, open_time, description, images) VALUES
(19, '宿城区政府站', '宿迁市宿城区政府大楼一楼', 34.008, 118.285, 1, '08:00-18:00', '政府大楼一楼大厅电梯旁，政务办事等待时免费充电', '["https://picsum.photos/seed/station19/400/300"]');
INSERT INTO stations (id, name, address, latitude, longitude, status, open_time, description, images) VALUES
